using System;
using System.Data;
using System.Data.SqlClient;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Azure.WebJobs;
using Microsoft.Azure.WebJobs.Extensions.Http;
using Microsoft.AspNetCore.Http;
using Microsoft.Extensions.Logging;

namespace AzureFunctions
{
    public static class ReportingAPI
    {
        [FunctionName("ReportingAPI")]
        public static IActionResult Run(
            [HttpTrigger(AuthorizationLevel.Anonymous, "get", Route = null)] HttpRequest req,
            ILogger log)
        {
            string connectionString = Environment.GetEnvironmentVariable("SQL_CONNECTION_STRING");
            string query = "SELECT * FROM customers WHERE ";

            // Validate untrusted input and use secure platform APIs
            if (req.Query.TryGetValue("name", out var name))
            {
                query += $"name LIKE '%{name}%' AND";
            }

            if (req.Query.TryGetValue("age", out var age))
            {
                query += $"age = {age} AND";
            }

            // Apply least privilege and explicit allowlists where relevant
            using (SqlConnection connection = new SqlConnection(connectionString))
            {
                connection.Open();
                using (SqlCommand command = new SqlCommand(query, connection))
                {
                    var result = command.ExecuteReader();
                    return new OkObjectResult(result);
                }
            }
        }
    }
